object ApiClient {
    private const val BASE_URL_DEV = "https://dev.example.com/users"
    private const val BASE_URL_STAGING = "https://staging.example.com/users"
    private const val BASE_URL_PROD = "https://api.example.com/users"

    fun getRetrofit(baseUrl: String, token: String): Retrofit {
        val client = OkHttpClient.Builder()
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .build()

        return Retrofit.Builder()
            .baseUrl(baseUrl)
            .client(client)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
